# ─── Particle ───────────────────────────────────────────────────────────────
class Particle:
    def __init__(self, x, y, color, vx=None, vy=None, life=None, size=None):
        self.x = x
        self.y = y
        self.color = color
        self.vx = vx if vx is not None else random.uniform(-8, 8)
        self.vy = vy if vy is not None else random.uniform(-8, 8)
        self.life = life if life is not None else random.randint(30, 70)
        self.max_life = self.life
        self.size = size if size is not None else random.randint(2, 6)
        self.ox = x
        self.oy = y
        self.snapping = False
        self.snap_timer = 0

    def update(self):
        if self.snapping:
            self.snap_timer += 1
            t = min(self.snap_timer / 20, 1.0)
            self.x += (self.ox - self.x) * 0.15
            self.y += (self.oy - self.y) * 0.15
            self.life -= 1
        else:
            self.x += self.vx
            self.y += self.vy
            self.vx *= 0.92
            self.vy *= 0.92
            self.life -= 1
            if self.life < self.max_life * 0.4:
                self.snapping = True

    def draw(self, surf):
        alpha = max(0, int(255 * self.life / self.max_life))
        r = max(0, min(255, self.color[0]))
        g = max(0, min(255, self.color[1]))
        b = max(0, min(255, self.color[2]))
        s = max(1, int(self.size * self.life / self.max_life))
        pygame.draw.circle(surf, (r, g, b), (int(self.x), int(self.y)), s)

# ─── Enemy ───────────────────────────────────────────────────────────────────
class Enemy:
    TYPES = ['triangle', 'hexagon', 'diamond']
    COLORS = {
        'triangle': TOXIC_GREEN,
        'hexagon': BURNING_ORANGE,
        'diamond': ICE_BLUE,
    }

    def __init__(self, level=1):
        self.etype = random.choice(self.TYPES)
        self.color = self.COLORS[self.etype]
        self.size = random.randint(14, 22)
        self.speed = 1.2 + level * 0.15 + random.uniform(0, 0.5)
        # Spawn from edges
        edge = random.randint(0, 3)
        if edge == 0:
            self.x = random.uniform(0, WIDTH)
            self.y = -30
        elif edge == 1:
            self.x = WIDTH + 30
            self.y = random.uniform(0, HEIGHT)
        elif edge == 2:
            self.x = random.uniform(0, WIDTH)
            self.y = HEIGHT + 30
        else:
            self.x = -30
            self.y = random.uniform(0, HEIGHT)
        self.angle = 0
        self.trail = []
        self.alive = True

    def update(self, target_x, target_y, slow_mo=False):
        speed = self.speed * (0.15 if slow_mo else 1.0)
        dx = target_x - self.x
        dy = target_y - self.y
        dist = math.hypot(dx, dy)
        if dist > 0:
            self.x += dx / dist * speed
            self.y += dy / dist * speed
        self.angle += 2
        self.trail.append((self.x, self.y))
        if len(self.trail) > 12:
            self.trail.pop(0)

    def draw(self, surf, palette_shift=0):
        # Draw ghost trail
        for i, (tx, ty) in enumerate(self.trail):
            alpha_ratio = i / len(self.trail)
            c = self._shifted_color(palette_shift)
            fade = int(80 * alpha_ratio)
            ts = max(1, int(self.size * 0.4 * alpha_ratio))
            pygame.draw.circle(surf, (min(255, c[0]), min(255, c[1]), min(255, c[2])),
                               (int(tx), int(ty)), ts)
        # Draw shape
        c = self._shifted_color(palette_shift)
        pts = self._get_points()
        if len(pts) >= 3:
            pygame.draw.polygon(surf, c, pts)
            pygame.draw.polygon(surf, WHITE, pts, 1)

    def _shifted_color(self, shift):
        if shift == 0:
            return self.color
        r = (self.color[0] + shift * 30) % 256
        g = (self.color[1] + shift * 50) % 256
        b = (self.color[2] + shift * 70) % 256
        return (r, g, b)

    def _get_points(self):
        cx, cy = int(self.x), int(self.y)
        ang = math.radians(self.angle)
        if self.etype == 'triangle':
            n = 3
        elif self.etype == 'hexagon':
            n = 6
        else:
            n = 4
        pts = []
        for i in range(n):
            a = ang + 2 * math.pi * i / n
            px = cx + self.size * math.cos(a)
            py = cy + self.size * math.sin(a)
            pts.append((px, py))
        return pts

    def get_rect(self):
        return pygame.Rect(self.x - self.size, self.y - self.size,
                           self.size * 2, self.size * 2)

# ─── Player ──────────────────────────────────────────────────────────────────
class Player:
    def __init__(self):
        self.x = WIDTH // 2
        self.y = HEIGHT // 2
        self.radius = 18
        self.pulse = 0
        self.alive = True
        self.invincible = 0

    def update(self, mx, my):
        self.x += (mx - self.x) * 0.18
        self.y += (my - self.y) * 0.18
        self.pulse += 0.1
        if self.invincible > 0:
            self.invincible -= 1

    def draw(self, surf):
        t = self.pulse
        ring_r = self.radius + 8 + int(4 * math.sin(t))
        # Outer pulsing ring
        pygame.draw.circle(surf, DEEP_VIOLET, (int(self.x), int(self.y)), ring_r + 4)
        pygame.draw.circle(surf, HOT_MAGENTA, (int(self.x), int(self.y)), ring_r, 3)
        # Core orb
        if self.invincible > 0 and (self.invincible // 4) % 2 == 0:
            pygame.draw.circle(surf, (200, 200, 255), (int(self.x), int(self.y)), self.radius)
        else:
            pygame.draw.circle(surf, WHITE, (int(self.x), int(self.y)), self.radius)
        # Inner glow
        pygame.draw.circle(surf, (180, 180, 255), (int(self.x), int(self.y)), self.radius - 5)

    def get_rect(self):
        return pygame.Rect(self.x - self.radius + 4, self.y - self.radius + 4,
                           (self.radius - 4) * 2, (self.radius - 4) * 2)

