# ─── Main Loop ───────────────────────────────────────────────────────────────
def main():
    print("VOID PULSE: Neon Abyss Survival - Starting...")
    print("Move mouse to control the orb. Survive the waves!")
    print("Thread through enemies to build combo multiplier.")

    game = Game()
    combo_check_timer = 0

    running = True
    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_ESCAPE:
                    running = False
                if event.key == pygame.K_r and game.game_over:
                    game = Game()
                    print("Game restarted!")

        if not game.game_over:
            game.update()

            # Check for threading (player near enemies but not touching)
            combo_check_timer += 1
            if combo_check_timer >= 10:
                combo_check_timer = 0
                pr = game.player.get_rect()
                pr_expanded = pr.inflate(60, 60)
                near_enemy = False
                for e in game.enemies:
                    if pr_expanded.colliderect(e.get_rect()):
                        near_enemy = True
                        break
                if near_enemy and game.player.invincible == 0:
                    game.thread_through()

            # Auto trigger pulse moment when all enemies cleared
            if (len(game.enemies) == 0 and not game.spawning_wave
                    and not game.slow_mo and not game.between_waves
                    and game.wave_timer < 10):
                pass  # handled in wave management

        game.draw(screen)
        pygame.display.flip()
        clock.tick(FPS)

    pygame.quit()
    print("Thanks for playing VOID PULSE!")
    sys.exit()


if __name__ == "__main__":
    main()